namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly Lock _lock = new();

    private readonly List<Notification> _notifications = [];

    public NotificationService()
    {
        // Seed with initial fake data.
        _notifications.AddRange(
        [
            MakeNotification("Welcome to the app!"),
            MakeNotification("Your profile was created."),
            MakeNotification("Check out the new features."),
        ]);
    }

    /// <summary>Returns all notifications.</summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return [.. _notifications];
        }
    }

    /// <summary>Returns only notifications with an Id greater than <paramref name="sinceId"/>.</summary>
    public List<Notification> GetSince(int sinceId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > sinceId).ToList();
        }
    }

    /// <summary>Simulates an external system pushing a new notification at random.</summary>
    public void SimulateIncoming()
    {
        var messages = new[]
        {
            "New comment on your post.",
            "Someone liked your photo.",
            "Server deployment succeeded.",
            "Your subscription is expiring soon.",
            "A new user signed up.",
            "Disk usage above 80%.",
        };

        lock (_lock)
        {
            var msg = messages[Random.Shared.Next(messages.Length)];
            _notifications.Add(MakeNotification(msg));
        }
    }

    private Notification MakeNotification(string message)
    {
        return new Notification(_nextId++, message, DateTime.UtcNow);
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using NotificationsApp.Services
@inject NotificationService NotificationSvc
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@_notifications.Count</span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications.OrderByDescending(x => x.Id))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = [];
    private CancellationTokenSource? _cts;

    // OnInitialized runs during BOTH prerender and interactive activation.
    // We load the initial data here so it appears in the server-rendered HTML.
    protected override void OnInitialized()
    {
        _notifications = NotificationSvc.GetAll();
    }

    // OnAfterRenderAsync with firstRender==true fires ONLY when the component
    // becomes interactive in the browser — never during static SSR prerender.
    // This is the safe place to start the polling loop.
    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender)
            return;

        _cts = new CancellationTokenSource();
        _ = PollForNotificationsAsync(_cts.Token);

        await Task.CompletedTask;
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);
            }
            catch (OperationCanceledException)
            {
                break;
            }

            // Simulate an external notification arriving.
            NotificationSvc.SimulateIncoming();

            var latestId = _notifications.Count > 0 ? _notifications.Max(n => n.Id) : 0;
            var newer = NotificationSvc.GetSince(latestId);

            if (newer.Count > 0)
            {
                _notifications.AddRange(newer);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

