namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly Lock _lock = new();

    private readonly List<Notification> _notifications = [];

    public NotificationService()
    {
        // Seed with initial fake data.
        _notifications.AddRange(
        [
            MakeNotification("Welcome to the app!"),
            MakeNotification("Your profile was created."),
            MakeNotification("Check out the new features."),
        ]);
    }

    /// <summary>Returns all notifications.</summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return [.. _notifications];
        }
    }

    /// <summary>Returns only notifications with an Id greater than <paramref name="sinceId"/>.</summary>
    public List<Notification> GetSince(int sinceId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > sinceId).ToList();
        }
    }

    /// <summary>Simulates an external system pushing a new notification at random.</summary>
    public void SimulateIncoming()
    {
        var messages = new[]
        {
            "New comment on your post.",
            "Someone liked your photo.",
            "Server deployment succeeded.",
            "Your subscription is expiring soon.",
            "A new user signed up.",
            "Disk usage above 80%.",
        };

        lock (_lock)
        {
            var msg = messages[Random.Shared.Next(messages.Length)];
            _notifications.Add(MakeNotification(msg));
        }
    }

    private Notification MakeNotification(string message)
    {
        return new Notification(_nextId++, message, DateTime.UtcNow);
    }
}

